#!/usr/bin/env bash
# solver-workflow-sim-node-lock-he.sh — Solver 研究 workflow（建翻前范围 → 跑 sim → 读节点/频率 → node-lock 剥削 → 抽象成 heuristic） SOP walkthrough for 德州扑克策略.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="德州扑克策略"
WORKFLOW="Solver 研究 workflow（建翻前范围 → 跑 sim → 读节点/频率 → node-lock 剥削 → 抽象成 heuristic）"

usage() {
  cat <<EOF
solver-workflow-sim-node-lock-he.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./solver-workflow-sim-node-lock-he.sh             # interactive
  ./solver-workflow-sim-node-lock-he.sh --dry-run
  ./solver-workflow-sim-node-lock-he.sh --json
  ./solver-workflow-sim-node-lock-he.sh --explain
  ./solver-workflow-sim-node-lock-he.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Solver 研究 workflow（建翻前范围 → 跑 sim → 读节点/频率 → node-lock 剥削 → 抽象成 heuristic）" 工作流。

一句话: 从「我不知道这个 spot 怎么打」到「我有一条能在牌桌上凭记忆套用的规则」——把 solver 的精确输出消化成可迁移直觉。 (evidence: [T03-S001, T03-S002])

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • GTO 基线 ⇄ 剥削偏离(equilibrium baseline ⇄ exploitative deviation): 先建一条**不可剥削的均衡基线 (GTO)**,再针对具体对手/人群的可观察漏洞**偏离 (exploit)** 去最大化 EV;GTO 是回得去的**锚点**,不是终点。
  • Range-first(先想范围,再想这手牌): 扑克决策的**原子单位是范围(对手在某节点所有可能持牌的概率分布)**,不是单张牌;高手把对手 put on a *range* 再随每条街的行动收窄。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**设定 spot 输入**:选位置 / 翻前线 / 有效码量 / rake;翻前范围用预解或 chart 锁定(GTO Wizard 预解树即点即用,或本地 solver 自建 bet tree)。 (evidence: [T03-S001])"
  "**跑 / 调出 sim**:云端站秒出预解,或本地 Pio/GTO+ 跑解(几分钟到几十分钟)。 (evidence: [T03-S001])"
  "**读节点 + 频率**:看动作频率、范围极化 vs 浓缩、关键阻断牌、EV 接近的边缘组合(indifference 点)。 (evidence: [T03-S005, T03-S006])"
  "**node-lock 做剥削**:锁定对手某节点的偏差频率(如「过度弃牌」),重解,看自己最大剥削策略变成什么。 (evidence: [T03-S007, T03-S009])"
  "**抽象成可记忆 heuristic**:把多个相似 sim 的共性压缩成一句话规则 + 例外条件,写进 study note。 (evidence: [T03-S002, T03-S005])"
)
declare -a FAILURE_MODES=(
  "**「solver 中毒」**:对每个 spot 都跑解、背点值,不抽象 heuristic → study 几百小时但牌桌反应慢。**避免**:每个 sim 必须产出一句可记忆规则才算读完;在 dev 跑解、回桌只用内化的 heuristic。"
  "**错误输入当真理**:用错码量/rake/范围跑解,把另一个游戏的均衡照搬实战 → 系统性打错。**避免**:跑解前先核对四要素(位置/线/有效码量/rake)与真实牌局一致。"
  "**单点 node-lock 当「最大剥削」**:以为锁一个节点就得到对真实对手的最大剥削,实则 solver 假设对手别处仍完美 GTO → 过度自信偏离反被反剥削。**避免**:用多点/迭代 lock,且只在样本足够支撑「对手确实这么偏」时才偏离。 (evidence: [T03-S008])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "solver-workflow-sim-node-lock-he-walkthrough"
fi
